                col = (ei_new + 1) / d_common.in2_sub2_rows + 1 - 1;
                if ((ei_new + 1) % d_common.in2_sub2_rows == 0) {
                    row = d_common.in2_sub2_rows - 1;
                    col = col - 1;
                }
                ori_row = row + d_common.in2_sub_cumh_sel2_rowlow - 1;
                ori_col = col + d_common.in2_sub_cumh_sel2_collow - 1;
                unique->d_in2_sqr_sub2[ei_new] = unique->d_in2_sub_cumh[ori_col * d_common.in2_sub_cumh_rows + ori_row];
            }

#pragma omp parallel for
            for (ei_new = 0; ei_new < d_common.in2_sub2_elem; ei_new++) {
                unique->d_in2_sqr_sub2[ei_new] = unique->d_in2_sub_cumh_sel[ei_new] - unique->d_in2_sqr_sub2[ei_new];
            }

#pragma omp parallel for private(temp, temp2)
            for (ei_new = 0; ei_new < d_common.in2_sub2_elem; ei_new++) {
                temp = unique->d_in2_sub2[ei_new];
                temp2 = unique->d_in2_sqr_sub2[ei_new] - (temp * temp / d_common.in_elem);
                if (temp2 < 0) temp2 = 0;
                unique->d_in2_sqr_sub2[ei_new] = sqrt(temp2) * denomT;
            }

#pragma omp parallel for
            for (ei_new = 0; ei_new < d_common.conv_elem; ei_new++) {
                unique->d_conv[ei_new] = unique->d_conv[ei_new] - unique->d_in2_sub2[ei_new] * mean * d_common.in_elem / d_common.in_elem;
            }

#pragma omp parallel for
            for (ei_new = 0; ei_new < d_common.in2_sub2_elem; ei_new++) {
                unique->d_in2_sqr_sub2[ei_new] = unique->d_conv[ei_new] / unique->d_in2_sqr_sub2[ei_new];
            }

            cent = d_common.sSize + d_common.tSize + 1;
            if (d_common_change.frame_no == 0) {
                tMask_row = cent + unique->d_Row[unique->point_no] - unique->d_Row[unique->point_no] - 1;
                tMask_col = cent + unique->d_Col[unique->point_no] - unique->d_Col[unique->point_no] - 1;
            } else {
                pointer = d_common_change.frame_no - 1 + unique->point_no * d_common.no_frames;
                tMask_row = cent + unique->d_tRowLoc[pointer] - unique->d_Row[unique->point_no] - 1;
                tMask_col = cent + unique->d_tColLoc[pointer] - unique->d_Col[unique->point_no] - 1;
            }

#pragma omp parallel for
            for (ei_new = 0; ei_new < d_common.tMask_elem; ei_new++) {
                if (ei_new == tMask_col * d_common.tMask_rows + tMask_row) {
                    unique->d_tMask[ei_new] = 1;
                } else {
                    unique->d_tMask[ei_new] = 0;
                }
            }

#pragma omp parallel for private(ic, jc, jp1, ja1, ja2, i, ip1, ia1, ia2, ja, jb, ia, ib, s, j, row)
            for (ei_new = 0; ei_new < d_common.mask_conv_elem; ei_new++) {
                ic = (ei_new + 1) % d_common.mask_conv_rows;
                jc = (ei_new + 1) / d_common.mask_conv_rows + 1;
                if ((ei_new + 1) % d_common.mask_conv_rows == 0) {
                    ic = d_common.mask_conv_rows;
                    jc = jc - 1;
                }
                j = jc + d_common.mask_conv_joffset;
                jp1 = j + 1;
                if (d_common.mask_cols < jp1) {
                    ja1 = jp1 - d_common.mask_cols;
                } else {
                    ja1 = 1;
                }
                if (d_common.tMask_cols < j) {
                    ja2 = d_common.tMask_cols;
                } else {
                    ja2 = j;
                }
                i = ic + d_common.mask_conv_ioffset;
                ip1 = i + 1;
                if (d_common.mask_rows < ip1) {
                    ia1 = ip1 - d_common.mask_rows;
                } else {
                    ia1 = 1;
                }
                if (d_common.tMask_rows < i) {
                    ia2 = d_common.tMask_rows;
                } else {
                    ia2 = i;
                }
                s = 0;
                for (ja = ja1; ja <= ja2; ja++) {
                    jb = jp1 - ja;
                    for (ia = ia1; ia <= ia2; ia++) {
                        ib = ip1 - ia;
                        s += unique->d_tMask[d_common.tMask_rows * (ja - 1) + ia - 1];
                    }
                }
                unique->d_mask_conv[ei_new] = unique->d_in2_sqr_sub2[ei_new] * s;
            }

            largest_value = 0;
            largest_coordinate = 0;
#pragma omp parallel for private(i, largest_value_current, largest_coordinate_current) reduction(max : largest_value)
            for (ei_new = 0; ei_new < d_common.mask_conv_rows; ei_new++) {
                for (i = 0; i < d_common.mask_conv_cols; i++) {
                    largest_coordinate_current = ei_new * d_common.mask_conv_rows + i;
                    largest_value_current = fabsf(unique->d_mask_conv[largest_coordinate_current]);
                    if (largest_value_current > largest_value) {
                        largest_coordinate = largest_coordinate_current;
                        largest_value = largest_value_current;
                    }
                }
            }

            largest_row = (largest_coordinate + 1) % d_common.mask_conv_rows - 1;
            largest_col = (largest_coordinate + 1) / d_common.mask_conv_rows;
            if ((largest_coordinate + 1) % d_common.mask_conv_rows == 0) {
                largest_row = d_common.mask_conv_rows - 1;
                largest_col = largest_col - 1;
            }
            largest_row = largest_row + 1;
            largest_col = largest_col + 1;
            offset_row = largest_row - d_common.in_rows - (d_common.sSize - d_common.tSize);
            offset_col = largest_col - d_common.in_cols - (d_common.sSize - d_common.tSize);
            pointer = d_common_change.frame_no + unique->point_no * d_common.no_frames;
            unique->d_tRowLoc[pointer] = unique->d_Row[unique->point_no] + offset_row;
            unique->d_tColLoc[pointer] = unique->d_Col[unique->point_no] + offset_col;
        }

        if (d_common_change.frame_no != 0 && (d_common_change.frame_no) % 10 == 0) {
            loc_pointer = unique->point_no * d_common.no_frames + d_common_change.frame_no;
            unique->d_Row[unique->point_no] = unique->d_tRowLoc[loc_pointer];
            unique->d_Col[unique->point_no] = unique->d_tColLoc[loc_pointer];

            d_in = &unique->d_T[unique->in_pointer];
#pragma omp parallel for private(row, col, ori_row, ori_col, ori_pointer)
            for (ei_new = 0; ei_new < d_common.in_elem; ei_new++) {
                row = (ei_new + 1) % d_common.in_rows - 1;
                col = (ei_new + 1) / d_common.in_rows + 1 - 1;
                if ((ei_new + 1) % d_common.in_rows == 0) {
                    row = d_common.in_rows - 1;
                    col = col - 1;
                }
                ori_row = unique->d_Row[unique->point_no] - 25 + row - 1;
                ori_col = unique->d_Col[unique->point_no] - 25 + col - 1;
                ori_pointer = ori_col * d_common.frame_rows + ori_row;
                d_in[ei_new] = d_common.alpha * d_in[ei_new] + (1.0f - d_common.alpha) * d_common_change.d_frame[ori_pointer];
            }
        }
    }
}
